 */

/**
 * @property
 * @name gridID
 * @category 09.Grid Settings
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description 그리드 아이디
 */

/**
 * @property
 * @name delFunction
 * @category 09.Grid Settings
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description 삭제 함수
 */

/**
 * @property
 * @name rowAddUserAuth
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description rowAdd 버튼 UserAuth
 */

/**
 * @property
 * @name rowDelUserAuth
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description rowDel 버튼 UserAuth
 */

/**
 * @property
 * @name delUserAuth
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description 삭제버튼 UserAuth
 */

/**
 * @property
 * @name rowAddObjType
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description rowAdd 버튼 ObjType
 */

/**
 * @property
 * @name rowDelObjType
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description rowDel 버튼 ObjType
 */

/**
 * @property
 * @name delObjType
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description 삭제버튼 ObjType
 */

/**
 * @property
 * @name cancelUserAuth
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description cancelUserAuth
 */

/**
 * @property
 * @name cancelObjType
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description desc
 */

/**
 * @property
 * @name btnDelYn
 * @category 05.Design
 * @type combobox
 * @option [Y,N]
 * @default Y
 * @necessary N
 * @bindparent
 * @description 삭제버튼 노출여부
 */

/**
 * @property
 * @name btnCancelYn
 * @category 05.Design
 * @type combobox
 * @option [Y,N]
 * @default N
 * @necessary N
 * @bindparent
 * @description 취소버튼 노출여부
 */

/**
 * @property
 * @name EngYn
 * @category 05.Design
 * @type combobox
 * @option [Y,N]
 * @default N
 * @necessary N
 * @bindparent
