 */

/**
 * @property
 * @name rowAddFunction
 * @category 09.Grid Settings
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description 행추가 함수
 */

/**
 * @property
 * @name btnRowAddYn
 * @category 05.Design
 * @type combobox
 * @option [Y,N]
 * @default Y
 * @necessary N
 * @bindparent
 * @description 그리드 행추가 버튼 노출 유무
 */

/**
 * @property
 * @name btnRowDelYn
 * @category 05.Design
 * @type combobox
 * @option [Y,N]
 * @default Y
 * @necessary N
 * @bindparent
 * @description 그리드 행삭제 버튼 노출유무
 */

/**
 * @property
 * @name rowDelFunction
 * @category 09.Grid Settings
 * @type string
